var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"안색이 나쁘네? 에델이 들려 준 얘기가 그렇게 충격적이었어?","JPN":"顔色が悪いね。エデルの話したことがそんなにショックだった？","ENG":"You don't look so good. Was Edel's story that much of a shock to you?","TWN":"妳臉色不太好耶？艾瑟兒說的這麼令人震驚嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네. 헛된 연구나 일삼는 사이비 패거리가 차라리 낫죠.","JPN":"ええ。くだらない研究ばかりしているインチキ集団の方がマシでしたね。","ENG":"Yes. It was better when they were just a group of stupid researchers studying nonsense.","TWN":"是啊，還不如天天做沒用研究的邪教學會呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"상상도 못했어요. 학회가 그런 끔직한 괴물이나 숭배하는 집단이었을 줄은.","JPN":"想像もできませんでした。学会がそんな恐ろしい怪物を崇拝する集団だったなんて。","ENG":"I never imagined that the Society was an organization of psychotic worshipers of those hideous monsters.","TWN":"我完全沒有想過，學會竟然是崇拜這種可怕怪物的集團。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......게다가 에델은 저 대신 학회장직을 맡은 처지잖아요.","JPN":"……それに、エデルは私の代わりに学会長を担っている立場なのですよね。","ENG":"Besides, Edel had to become the President because I wasn't around.","TWN":"……況且艾瑟兒還代替我接任了學會長一職。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 고향을 떠나지 않았더라면 그럴 필요도 없었을 텐데......","JPN":"私が故郷を離れなければ、そんな必要も無かったのに……","ENG":"Things could have turned out differently for her if I hadn't left home.","TWN":"若不是我離開了家鄉，妳也就不需要這麼做了……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"이미 지나간 일을 뭐 하러 고민해?","JPN":"もう過ぎたことを悩んでどうするの？","ENG":"What happened happened. There's no point in brooding over the past.","TWN":"都是過去的事了，有什麼好煩惱的？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그냥 잊어 버려. 에델도 적성에 맞아 하는 것 같은데.","JPN":"もう忘れちゃいなって。エデルも性に合ってるみたいだし。","ENG":"Just forget it. Besides, Edel seems to like what she does.","TWN":"忘了吧。反正這工作似乎也很適合艾瑟兒。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"말이 된다고 생각해요? 이런 일을 어떻게 잊고 살 수 있어요?","JPN":"できると思いますか？　こんなことを忘れて暮らすなんて。","ENG":"Do you think I could do that? How could I ever forget such things?","TWN":"妳覺得這有可能嗎？我要怎麼忘記這種事情？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"원래 떠올리기 싫은 기억은 머릿속 깊숙이 묻어 두는 거야.","JPN":"元々、思い出したくない記憶なんて頭の奥底に埋めておくものだよ。","ENG":"If you have memories that you don't want to recall, you bury them deep within your heart.","TWN":"不願回憶起的記憶本來就該深埋在腦中啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"믿었던 사람에게 배신 당했다거나, 총알 살 돈이 다 떨어졌다거나.","JPN":"信じてた人に裏切られたとか、銃弾を買うお金も無くなったとか。","ENG":"Being betrayed by someone you trusted, running out of money for ammo...","TWN":"比如說被信任的人背叛，或是買子彈的錢用完了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그런 일을 억지로 붙들고 살다 보면 머리가 갑자기 돌아버릴 수도 있거든.","JPN":"そんなことをイチイチ全部覚えてたら、頭がどうにかなっちゃうしね。","ENG":"Life is full of despair, and you'll lose your mind if you hold onto it too much.","TWN":"要是強迫自己記得這些事情，說不定哪天突然就瘋掉了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"레지나는 살면서 그런 일 겪어 본 적 없어?","JPN":"レジーナは今まで生きててそういう経験ないの？","ENG":"Haven't you had such experiences in your life, Regina?","TWN":"蕾佳娜活到現在有經歷過這種事嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"멍청한 계집애 같으니!","JPN":"馬鹿な娘ね！","ENG":"You're a disgrace!","TWN":"妳這個蠢丫頭！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_05"},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"제물 손질 하나 제대로 못하면서 무슨 후계자야!","JPN":"供物も捌けないで後継者になれると思っているの！","ENG":"How could you call yourself the family heir when you can't even prepare an offering properly?","TWN":"連一個祭品都處理不好，還算什麼繼承者！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"그, 그치만 엄마...... 얘 아직 살아 있는데......","JPN":"で、でもママ……この子、まだ生きてるのに……","ENG":"B-but Mom, it's still alive...","TWN":"但、但是媽媽……那孩子還活著啊……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"더러운 배신자......! 그 배신자 놈이 우리 집안을 망쳐 버렸어!","JPN":"卑怯な裏切り者め……！　あの裏切り者のせいで我が家はメチャクチャよ！","ENG":"That filthy traitor! He ruined everything for all of us!","TWN":"骯髒的叛徒……！那個叛徒毀了我們家！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"우리 가문이 어떤 가문인데! 배신자의 더러운 핏줄 따위에 넘겨 줄까 봐!","JPN":"マクレディー家がどんな家系だかわかっているの！？\\n裏切り者の汚れた血を引く娘なんかに譲るものか！","ENG":"He disgraced the great Family MacCready! I won't hand my family over to that filthy betrayer or his kin!","TWN":"我們是什麼家族！怎麼可以把家族交給叛徒骯髒的血脈！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"자, 잘못했어요...... 엄마, 잘못했어요......","JPN":"ご、ごめんなさい……ママ……ごめんなさい……","ENG":"I-I’m sorry! I'm sorry, Mom...","TWN":"我、我錯了……媽媽，我錯了……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"시끄러!","JPN":"うるさい！","ENG":"Shut it!","TWN":"吵死了！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"왜 하필 너야! 왜 하필 너냐고!","JPN":"どうしてよりによってお前なの！　どうして！","ENG":"Why does it have to be you? Why?","TWN":"為什麼是妳！為什麼偏偏是妳！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"죽어! 이 망할 계집애 같으니! 죽어!!","JPN":"死になさい！　この役立たず！　死ぬのよ！！","ENG":"Die, you stupid little rat! Die!","TWN":"去死！妳這該死的丫頭！去死吧！！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"엄마...... 숨...... 막혀...... 엄마......","JPN":"ママ……息が……苦しい……ママ……","ENG":"Mom... I... I can't breathe... Mom...","TWN":"媽媽……沒辦法……呼吸……媽媽……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"설령 그 말이 맞다고 해도, 싫은 기억을 떠올리도록 부추기는 게 좋아 보이진 않네요.","JPN":"たとえあなたの言うとおりだとしても、嫌な記憶を思い出させるのは良くないと思いますわ。","ENG":"Even if you're right, you shouldn't be encouraging me to recall bad memories.","TWN":"就算妳說得沒錯，煽動別人想起討厭的回憶也不是什麼好事呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"꺄하하! 당연하지! 난 원래 나쁜 사람이니까!","JPN":"キャハハ！　当たり前でしょ！　アタシは元々悪者だから！","ENG":"Kya hah hah! Well, duh! I'm bad like that!","TWN":"哈哈哈！那當然！誰叫我本來就是壞人！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아. 물론 그 중에선 쬐끔 덜 나쁜 편이지만.","JPN":"ああ、もちろん悪者の中では悪くない方だけどさ。","ENG":"Although, I'm not as bad as some of the bad people that I took care of.","TWN":"啊，當然，是壞人中沒那麼壞的那個。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......쉴 만큼 쉬었으니 그만 움직이죠.","JPN":"……十分に休んだようなので、そろそろ動きましょう。","ENG":"I think we've rested enough. Let's get going.","TWN":"……休息得夠久了，我們差不多該走了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"오? 계속 같이 다니게?","JPN":"あれ？　これからも一緒に動く気？","ENG":"Oh? You're going to keep tagging along?","TWN":"哦？妳要繼續和我們一起走？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"못 해 먹겠다고 때려치울 줄 알았더니?","JPN":"やってられないって断ると思ったのに。","ENG":"I thought you were going to quit and leave.","TWN":"我還以為妳會打退堂鼓呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"괴물로 변했어도 어머니의 시신이에요.","JPN":"怪物になったとしても、お母様の遺体ですから。","ENG":"Even though she became a monster, she's still my mother.","TWN":"就算變成了怪物，那也是母親的遺體。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"사람을 해치고 다니게 둘 수는 없죠. 가문의 명예가 걸린 일입니다.","JPN":"人を害するのを放置するわけにはいきません。マクレディー家の名誉もかかっていますし。","ENG":"I can't let her run around, hurting people. The honor of my family rests upon this.","TWN":"我不能放任它去害人，這關係到家族的名譽。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이렇게 된 이상 꼭 찾아내서...... 막을 수밖에 없어요.","JPN":"こうなった以上、何が何でも見つけ出して……止めるしかありませんね。","ENG":"I've come this far anyway. I'm going to find her and stop her.","TWN":"既然事情已經變成這樣了，那就一定要找到它……然後阻止它。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"응, 응. 카운터가 협조해 주면 나야 환영이지.","JPN":"うんうん。カウンターが協力してくれるなら、アタシは大歓迎だよ。","ENG":"Glad to hear that. A Counter's help is always appreciated.","TWN":"嗯，嗯。有制裁者幫忙我當然是很歡迎啦。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그럼 난 네 어머니를 찾으러 가 볼게.","JPN":"じゃあ、アタシはアンタのお母さんを探しに行くね。","ENG":"Then I'll go find your mom.","TWN":"那我就去找妳的母親了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"표식을 남겨 놓을 테니까 에델이랑 같이 천천히 와.","JPN":"印を付けておくから、エデルと一緒にゆっくりおいで。","ENG":"I'll leave marks behind. Come after me with Edel.","TWN":"我會留下標記的，妳和艾瑟兒就慢慢跟來吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"잠깐만요. 리벳.","JPN":"待ってください、リベット。","ENG":"Wait, Rivet.","TWN":"等一下，里維。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"응? 왜?","JPN":"ん？　どうした？","ENG":"Hm? What is it?","TWN":"嗯？怎麼了？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"질문을 듣고 갑자기 궁금해졌어요.","JPN":"質問を聞いて、急に気になったのですが……","ENG":"Your question made me wonder.","TWN":"聽了剛才的問題，我突然有些好奇。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신에게도...... 떠올리기 싫은 기억이 있나요?","JPN":"あなたにも……思い出したくない記憶はありますか？","ENG":"Do you have memories that you don't want to recall?","TWN":"妳也……有什麼不願想起的回憶嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"너도 참 무슨 소릴 하는 거야?","JPN":"アンタ、何言ってるの？","ENG":"Come on, Regina.","TWN":"妳也真是的，在說些什麼啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그런 건 떠올리고 싶은 기억이 있는지부터 물어 보는 게 매너라구.","JPN":"そういう時は思い出したい記憶があるか聞くのがマナーってもんでしょ。","ENG":"Don't you think you should first ask if I have memories that I want to recall?","TWN":"應該先問有什麼想要想起的回憶才有禮貌吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"왜 내 말을 듣지 않는 거야......! 이깟 계집이 뭐라고!","JPN":"どうして私の言うことを聞かないの……！　こんな娘が何だっていうの！","ENG":"Why won't you listen to me? Why are you defending this little wench?","TWN":"為什麼不聽我的話啊……！區區一個臭丫頭！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그<color=#ff3636>만하</color>세요. 부<color=#ff3636>인</color>.","JPN":"も<color=#ff3636>うや</color>めてください。夫<color=#ff3636>人</color>。","ENG":"Calm do<color=#ff3636>wn</color>, Mrs. Mac<color=#ff3636>Cready</color>.","TWN":"請<color=#ff3636>住手</color>吧。夫<color=#ff3636>人</color>。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇게 목<color=#ff3636>을 조르</color>면 뇌에 피<color=#ff3636>가 통하</color>지 않아서 금<color=#ff3636>방 죽</color>어 버려요.","JPN":"そんなに首<color=#ff3636>を絞め</color>たら、脳に血<color=#ff3636>が通わな</color>くなってす<color=#ff3636>ぐに死</color>んでしまいますよ。","ENG":"Strang<color=#ff3636>ling</color> her like that will b<color=#ff3636>lock</color> the flow of blood to her brain and kill her even<color=#ff3636>tually</color>.","TWN":"這<color=#ff3636>樣掐</color>住脖子的話，血<color=#ff3636>液無法流</color>到腦部，很<color=#ff3636>快就會死</color>掉的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"저 계집을 당장 잡아먹어!! 어서!","JPN":"あの娘を今すぐに食べなさい！！　早く！","ENG":"Eat that little rat! Now!","TWN":"馬上吃掉這個臭丫頭！！快點！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>다</color>정한 아<color=#ff3636>이잖</color>아요. 저희도 기<color=#ff3636>대가 크</color>답니다.","JPN":"<color=#ff3636>優</color>しい子<color=#ff3636>で</color>す。我々も期<color=#ff3636>待してい</color>るんですよ。","ENG":"She's a s<color=#ff3636>weet</color> ch<color=#ff3636>ild</color>. We have high expect<color=#ff3636>ations</color> for her.","TWN":"<color=#ff3636>她不</color>是個溫<color=#ff3636>柔的孩</color>子嗎？我們對她也有<color=#ff3636>很大的期</color>待。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"레지<color=#ff3636>나 님은</color> 분명, 훌륭<color=#ff3636>한 학회</color>장이 되어 주실 거예요.","JPN":"レジー<color=#ff3636>ナ様は</color> きっと、立派<color=#ff3636>な学会</color>長になるでしょう。","ENG":"Re<color=#ff3636>gina</color> will make a great president of the So<color=#ff3636>ciety</color>.","TWN":"蕾佳<color=#ff3636>娜大人</color>肯定會成為優秀<color=#ff3636>的學會</color>長。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저에겐......","JPN":"私には……","ENG":"Such memories","TWN":"我……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런 기억 따위 없어요.","JPN":"そんな記憶はありません。","ENG":"do not exist in me.","TWN":"沒有這種回憶。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};